import { Component, OnInit, ViewChild, ElementRef, HostListener } from '@angular/core';

@Component({
  selector: 'app-trailer',
  templateUrl: './trailer.component.html',
  styleUrls: ['./trailer.component.css']
})
export class TrailerComponent implements OnInit {
  @ViewChild('videoContainer') videoContainer!: ElementRef;
  isVideoPlaying = false;

  constructor() { }

  ngOnInit(): void {
  }

  @HostListener('window:scroll')
  onWindowScroll(): void {
    if (!this.videoContainer) return;
    
    const element = this.videoContainer.nativeElement;
    const rect = element.getBoundingClientRect();
    const isVisible = rect.top < window.innerHeight && rect.bottom > 0;
    
    if (isVisible && !this.isVideoPlaying) {
      // Video will autoplay when visible (video element has autoplay attribute)
    }
  }

  onVideoPlay() {
    this.isVideoPlaying = true;
  }
}
<section class="trailer" id="trailer">
  <div class="trailer-container">
    <h2 class="trailer-title">Watch the Trailer</h2>
    <div class="video-container" #videoContainer>
      <iframe
        width="100%"
        height="600"
        src="https://www.youtube.com/embed/MX96CbC9q34?autoplay=1&mute=1"
        title="Glumion Trailer"
        allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture"
        allowfullscreen>
      </iframe>
    </div>
  </div>
</section>
